/* ====== AI 配色: 从 deco 照片取色生成设计 ====== */
function _mix(c, target, p) {
  return { r: c.r + (target - c.r) * p, g: c.g + (target - c.g) * p, b: c.b + (target - c.b) * p };
}
function _hex(c) {
  return "#" + [c.r, c.g, c.b].map(v => Math.round(Math.max(0, Math.min(255, v))).toString(16).padStart(2, "0")).join("");
}
function _dist(a, b) { return Math.abs(a.r - b.r) + Math.abs(a.g - b.g) + Math.abs(a.b - b.b); }
function extractPalette(src) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      try {
        const cv = document.createElement("canvas");
        const s = Math.min(1, 90 / Math.max(img.width, img.height));
        cv.width = Math.max(1, Math.round(img.width * s));
        cv.height = Math.max(1, Math.round(img.height * s));
        const ctx = cv.getContext("2d");
        ctx.drawImage(img, 0, 0, cv.width, cv.height);
        const data = ctx.getImageData(0, 0, cv.width, cv.height).data;
        const buckets = {};
        for (let i = 0; i < data.length; i += 4) {
          const r = data[i], g = data[i + 1], b = data[i + 2];
          const key = (r >> 5) + "," + (g >> 5) + "," + (b >> 5);
          const e = buckets[key] || { r: 0, g: 0, b: 0, n: 0 };
          e.r += r; e.g += g; e.b += b; e.n++;
          buckets[key] = e;
        }
        const cols = Object.values(buckets).map(e => ({ r: e.r / e.n, g: e.g / e.n, b: e.b / e.n, n: e.n }));
        const sat = c => { const mx = Math.max(c.r, c.g, c.b), mn = Math.min(c.r, c.g, c.b); return mx === 0 ? 0 : (mx - mn) / mx; };
        cols.sort((a, b) => b.n * Math.pow(sat(b) + 0.05, 1.3) - a.n * Math.pow(sat(a) + 0.05, 1.3));
        const accent = cols[0] || { r: 84, g: 112, b: 142 };
        const second = cols.find(c => _dist(c, accent) > 110) || _mix(accent, 200, 0.4);
        const theme = {
          id: "custom", name: "AI 配色",
          bg: _hex(_mix(accent, 255, 0.93)),
          card: "#ffffff",
          ink: _hex(_mix(accent, 0, 0.72)),
          soft: _hex(_mix(accent, 140, 0.55)),
          accent: _hex(_mix(accent, 0, 0.12)),
          gold: _hex(second),
          line: _hex(_mix(accent, 255, 0.8)),
        };
        resolve(theme);
      } catch (e) { reject(e); }
    };
    img.onerror = reject;
    img.src = src;
  });
}

